#[test]
fn all_16_categories_convert_to_problem() {
    cf_modkit_errors::resource_error!(R, "gts.cf.core.users.user.v1~");

    let errors: Vec<CanonicalError> = vec![
        R::cancelled().create(),
        R::unknown("unknown error").create(),
        R::invalid_argument()
            .with_field_violation("field", "bad format", "INVALID_FORMAT")
            .create(),
        R::deadline_exceeded("timed out").create(),
        R::not_found("Resource not found")
            .with_resource("user-123")
            .create(),
        R::already_exists("Resource already exists")
            .with_resource("user-123")
            .create(),
        R::permission_denied().create(),
        R::resource_exhausted("Quota exceeded")
            .with_quota_violation("requests", "limit reached")
            .create(),
        R::failed_precondition()
            .with_precondition_violation("state", "not ready", "STATE")
            .create(),
        R::aborted("concurrency conflict")
            .with_reason("OPTIMISTIC_LOCK_FAILURE")
            .create(),
        R::out_of_range("Value out of range")
            .with_field_violation("page", "beyond last page", "OUT_OF_RANGE")
            .create(),
        R::unimplemented("not implemented").create(),
        CanonicalError::internal("bug").create(),
        CanonicalError::service_unavailable()
            .with_retry_after_seconds(10)
            .create(),
        R::data_loss("data loss").with_resource("user-123").create(),
        CanonicalError::unauthenticated()
            .with_reason("MISSING_CREDENTIALS")
            .create(),
    ];
    assert_eq!(errors.len(), 16);
    for err in errors {
        let problem = Problem::from(err);
        assert!(!problem.problem_type.is_empty());
        assert!(!problem.title.is_empty());
        assert!(problem.status > 0);
    }
}

#[test]
fn io_error_converts_to_internal_canonical_error() {
    let err = std::io::Error::new(std::io::ErrorKind::NotFound, "missing config");

    let canonical = CanonicalError::from(err);

    assert_eq!(canonical.status_code(), 500);
    assert_eq!(canonical.title(), "Internal");
}

#[test]
fn serde_json_error_converts_to_invalid_argument_canonical_error() {
    let err = serde_json::from_str::<serde_json::Value>("not json").unwrap_err();
    let expected_detail = err.to_string();

    let canonical = CanonicalError::from(err);

    assert_eq!(canonical.status_code(), 400);
    assert_eq!(canonical.title(), "Invalid Argument");
    assert_eq!(canonical.detail(), expected_detail);
}

#[test]
fn question_mark_propagates_io_error_as_canonical_error() {
    fn read_missing_file() -> Result<(), CanonicalError> {
        std::fs::read_to_string("__cf_modkit_errors_missing_file__")?;
        Ok(())
    }

    let canonical = read_missing_file().unwrap_err();

    assert_eq!(canonical.status_code(), 500);
    assert_eq!(canonical.title(), "Internal");
}

#[test]
fn question_mark_propagates_serde_json_error_as_canonical_error() {
    fn parse_invalid_json() -> Result<serde_json::Value, CanonicalError> {
        Ok(serde_json::from_str("not json")?)
    }

    let direct_err = serde_json::from_str::<serde_json::Value>("not json").unwrap_err();
    let expected_detail = direct_err.to_string();
    let canonical = parse_invalid_json().unwrap_err();

    assert_eq!(canonical.status_code(), 400);
    assert_eq!(canonical.title(), "Invalid Argument");
    assert_eq!(canonical.detail(), expected_detail);
}

